204	export type NumericInputEvent =
205	  | { kind: 'start'; firstDigit: string }
206	  | { kind: 'append'; digit: string }
207	  | { kind: 'backspace' }
208	  | { kind: 'tab-axis' }
209	  | { kind: 'commit' }
210	  | { kind: 'cancel' };
211	
212	export function reduceNumericInput(
213	  state: NumericInputState,
214	  event: NumericInputEvent,
215	): NumericInputState {
216	  switch (event.kind) {
217	    case 'start':
218	      return { active: true, value: event.firstDigit, axis: 'primary' };
219	    case 'append':
220	      if (!state.active) return state;
221	      return { ...state, value: state.value + event.digit };
222	    case 'backspace':
223	      if (!state.active) return state;
224	      return { ...state, value: state.value.slice(0, -1) };
225	    case 'tab-axis':
226	      if (!state.active) return state;
227	      return {
228	        ...state,
229	        axis: state.axis === 'primary' ? 'perpendicular' : 'primary',
230	      };
231	    case 'commit':
232	    case 'cancel':
233	      return initialNumericInputState();
234	  }
235	}
