    bumpGeom((x) => x + 1);
    return;
  }
  const dx = sp.xMm - d.ax;
  const dy = sp.yMm - d.ay;
  const m = Math.hypot(dx, dy) || 1;
  onSemanticCommand({
    type: 'createDimension',
    levelId: lvlId,
    aMm: { xMm: d.ax, yMm: d.ay },
    bMm: { xMm: sp.xMm, yMm: sp.yMm },
    offsetMm: { xMm: (-dy / m) * 450, yMm: (dx / m) * 450 },
