    const foreign: Extract<Element, { kind: 'leader_text' }> = {
      ...leaderText,
      id: 'lt-other',
      hostViewId: OTHER_VIEW,
    };
    const prims = extractDetailComponentPrimitives({ [foreign.id]: foreign }, VIEW);
    expect(prims).toEqual([]);
  });
});

