2	 * EDT-01 — column grip provider.
3	 *
4	 * Position grip at the column's footprint centre. A separate rotation
5	 * handle is emitted for non-square columns (b ≠ h); square columns
6	 * have rotational symmetry so the rotation handle would be a no-op.
7	 *
8	 * Drag-commits use `updateElementProperty` with JSON-encoded values
9	 * (consistent with the floor `boundaryMm` pattern) so the engine path
10	 * doesn't need a bespoke MoveColumn command.
11	 */
12	import type { Element } from '@bim-ai/core';
13	
14	import type {
15	  ElementGripProvider,
16	  GripCommand,
17	  GripDescriptor,
18	  PlanContext,
19	} from '../gripProtocol';
20	
21	export type Column = Extract<Element, { kind: 'column' }>;
22	
23	const ROTATION_HANDLE_OFFSET_MM = 200;
24	
25	export const columnGripProvider: ElementGripProvider<Column> = {
26	  grips(column: Column, _context: PlanContext): GripDescriptor[] {
27	    const grips: GripDescriptor[] = [];
28	    const positionGrip: GripDescriptor = {
29	      id: `${column.id}:position`,
30	      positionMm: column.positionMm,
31	      shape: 'square',
32	      axis: 'free',
33	      hint: 'Drag to move column',
34	      onDrag: () => ({ kind: 'unknown', id: column.id }),
35	      onCommit: (delta): GripCommand => ({
36	        type: 'updateElementProperty',
37	        elementId: column.id,
38	        key: 'positionMm',
39	        value: JSON.stringify({
40	          xMm: column.positionMm.xMm + delta.xMm,
41	          yMm: column.positionMm.yMm + delta.yMm,
42	        }),
43	      }),
44	      onNumericOverride: (absoluteMm): GripCommand => ({
45	        // Numeric override on a 2D position is interpreted as the new
46	        // X coordinate; Y is left unchanged. The grammar polish (EDT-06)
47	        // can swap this for an axis-aware Tab cycle later.
48	        type: 'updateElementProperty',
49	        elementId: column.id,
50	        key: 'positionMm',
51	        value: JSON.stringify({ xMm: absoluteMm, yMm: column.positionMm.yMm }),
52	      }),
53	    };
54	    grips.push(positionGrip);
55	
56	    // Non-square columns get a rotation handle offset normal to the
57	    // long axis of the footprint. We pick the handle along +X by
58	    // default; the canvas rotates it by `rotationDeg` for display.
59	    if (column.bMm !== column.hMm) {
60	      const rotation = column.rotationDeg ?? 0;
61	      const rad = (rotation * Math.PI) / 180;
62	      const handleX = column.positionMm.xMm + Math.cos(rad) * ROTATION_HANDLE_OFFSET_MM;
63	      const handleY = column.positionMm.yMm + Math.sin(rad) * ROTATION_HANDLE_OFFSET_MM;
64	      const rotationGrip: GripDescriptor = {
65	        id: `${column.id}:rotation`,
66	        positionMm: { xMm: handleX, yMm: handleY },
67	        shape: 'arrow',
68	        axis: 'free',
69	        hint: 'Drag to rotate column',
70	        onDrag: () => ({ kind: 'unknown', id: column.id }),
71	        onCommit: (delta): GripCommand => {
72	          const dx = handleX - column.positionMm.xMm + delta.xMm;
73	          const dy = handleY - column.positionMm.yMm + delta.yMm;
74	          const nextDeg = (Math.atan2(dy, dx) * 180) / Math.PI;
75	          return {
76	            type: 'updateElementProperty',
77	            elementId: column.id,
78	            key: 'rotationDeg',
