import { describe, it, expect } from 'vitest';
import type { Element } from '@bim-ai/core';

import { textNoteGripProvider, leaderTextGripProvider } from './annotationGripProvider';

const textNote: Extract<Element, { kind: 'text_note' }> = {
  kind: 'text_note',
  id: 'tn-1',
  hostViewId: 'pv-1',
  positionMm: { xMm: 1000, yMm: 2000 },
  text: 'Hello',
  fontSizeMm: 200,
};

const leaderText: Extract<Element, { kind: 'leader_text' }> = {
  kind: 'leader_text',
  id: 'lt-1',
  hostViewId: 'pv-1',
  anchorMm: { xMm: 0, yMm: 0 },
  elbowMm: { xMm: 300, yMm: 0 },
  textMm: { xMm: 600, yMm: 0 },
  content: 'Wall type A',
};

describe('textNoteGripProvider', () => {
  it('emits one position grip at the text note position', () => {
    const grips = textNoteGripProvider.grips(textNote, {});
    expect(grips).toHaveLength(1);
    expect(grips[0]!.id).toBe('tn-1:position');
    expect(grips[0]!.positionMm).toEqual({ xMm: 1000, yMm: 2000 });
    expect(grips[0]!.shape).toBe('square');
    expect(grips[0]!.axis).toBe('free');
  });

  it('onCommit produces updateElementProperty for positionMm with delta applied', () => {
    const [grip] = textNoteGripProvider.grips(textNote, {});
    const cmd = grip!.onCommit({ xMm: 100, yMm: -50 });
    expect(cmd.type).toBe('updateElementProperty');
    expect(cmd.elementId).toBe('tn-1');
    expect(cmd.key).toBe('positionMm');
    const parsed = JSON.parse(cmd.value as string) as { xMm: number; yMm: number };
    expect(parsed).toEqual({ xMm: 1100, yMm: 1950 });
  });

  it('onNumericOverride sets X coordinate leaving Y unchanged', () => {
    const [grip] = textNoteGripProvider.grips(textNote, {});
    const cmd = grip!.onNumericOverride(5000);
    const parsed = JSON.parse(cmd.value as string) as { xMm: number; yMm: number };
    expect(parsed.xMm).toBe(5000);
    expect(parsed.yMm).toBe(2000);
  });
});

describe('leaderTextGripProvider', () => {
  it('emits two grips: anchor (circle) and text-block (square)', () => {
    const grips = leaderTextGripProvider.grips(leaderText, {});
    expect(grips).toHaveLength(2);
    const anchorGrip = grips.find((g) => g.id === 'lt-1:anchor');
    const textGrip = grips.find((g) => g.id === 'lt-1:text');
    expect(anchorGrip).toBeDefined();
    expect(textGrip).toBeDefined();
    expect(anchorGrip!.shape).toBe('circle');
    expect(textGrip!.shape).toBe('square');
  });

  it('anchor grip onCommit moves anchorMm by delta', () => {
    const grips = leaderTextGripProvider.grips(leaderText, {});
    const anchorGrip = grips.find((g) => g.id === 'lt-1:anchor')!;
    const cmd = anchorGrip.onCommit({ xMm: 50, yMm: 100 });
    expect(cmd.key).toBe('anchorMm');
    const parsed = JSON.parse(cmd.value as string) as { xMm: number; yMm: number };
    expect(parsed).toEqual({ xMm: 50, yMm: 100 });
  });

  it('text grip onCommit moves textMm by delta independently of anchor', () => {
    const grips = leaderTextGripProvider.grips(leaderText, {});
    const textGrip = grips.find((g) => g.id === 'lt-1:text')!;
    const cmd = textGrip.onCommit({ xMm: -200, yMm: 50 });
    expect(cmd.key).toBe('textMm');
    const parsed = JSON.parse(cmd.value as string) as { xMm: number; yMm: number };
    expect(parsed).toEqual({ xMm: 400, yMm: 50 });
  });
});

/**
 * EDT-01 — grip provider registry.
 *
 * Single dispatch point used by PlanCanvas to fetch grips for a
 * selected element. Providers are pure functions of `(element,
 * context)` so callers can also import a specific provider for unit
 * tests without going through the registry.
 */
import type { Element } from '@bim-ai/core';

import { wallGripProvider } from '../gripProtocol';
import type { GripDescriptor, PlanContext } from '../gripProtocol';

import { beamGripProvider } from './beamGripProvider';
import { columnGripProvider } from './columnGripProvider';
import { dimensionGripProvider } from './dimensionGripProvider';
import { doorGripProvider } from './doorGripProvider';
import { floorGripProvider } from './floorGripProvider';
import { maskingRegionGripProvider } from './maskingRegionGripProvider';
import { placedAssetGripProvider } from './placedAssetGripProvider';
import { referencePlaneGripProvider } from './referencePlaneGripProvider';
import { sectionCutGripProvider } from './sectionCutGripProvider';
import { sketchElementGripProvider } from './sketchElementGripProvider';
import { windowGripProvider } from './windowGripProvider';
import { textNoteGripProvider, leaderTextGripProvider } from './annotationGripProvider';

export {
  beamGripProvider,
  columnGripProvider,
  dimensionGripProvider,
  doorGripProvider,
  floorGripProvider,
  maskingRegionGripProvider,
  placedAssetGripProvider,
  referencePlaneGripProvider,
  sectionCutGripProvider,
  sketchElementGripProvider,
  windowGripProvider,
  textNoteGripProvider,
  leaderTextGripProvider,
};

export function gripsFor(element: Element, context: PlanContext = {}): GripDescriptor[] {
  switch (element.kind) {
    case 'wall':
      return wallGripProvider.grips(element, context);
    case 'door':
      return doorGripProvider.grips(element, context);
    case 'window':
      return windowGripProvider.grips(element, context);
    case 'floor':
      return floorGripProvider.grips(element, context);
    case 'masking_region':
      return maskingRegionGripProvider.grips(element, context);
    case 'column':
      return columnGripProvider.grips(element, context);
    case 'beam':
      return beamGripProvider.grips(element, context);
    case 'section_cut':
      return sectionCutGripProvider.grips(element, context);
    case 'dimension':
      return dimensionGripProvider.grips(element, context);
    case 'reference_plane':
      return referencePlaneGripProvider.grips(element, context);
    case 'placed_asset':
      return placedAssetGripProvider.grips(element, context);
    case 'plan_region':
    case 'stair':
      return sketchElementGripProvider.grips(element, context);
    case 'text_note':
      return textNoteGripProvider.grips(element, context);
    case 'leader_text':
      return leaderTextGripProvider.grips(element, context);
    default:
      return [];
  }
}

/**
 * ANN-01/ANN-16 — grip providers for view-local annotation elements.
 *
 * text_note: single position grip to drag the whole label.
 * leader_text: anchor grip + text-block grip (move independently).
 */
import type { Element } from '@bim-ai/core';

import type {
  ElementGripProvider,
  GripCommand,
  GripDescriptor,
  PlanContext,
} from '../gripProtocol';

export type TextNote = Extract<Element, { kind: 'text_note' }>;
export type LeaderText = Extract<Element, { kind: 'leader_text' }>;

export const textNoteGripProvider: ElementGripProvider<TextNote> = {
  grips(el: TextNote, _ctx: PlanContext): GripDescriptor[] {
    const positionGrip: GripDescriptor = {
      id: `${el.id}:position`,
      positionMm: el.positionMm,
      shape: 'square',
      axis: 'free',
      hint: 'Drag to move text',
      onDrag: () => ({ kind: 'unknown', id: el.id }),
      onCommit: (delta): GripCommand => ({
        type: 'updateElementProperty',
        elementId: el.id,
        key: 'positionMm',
        value: JSON.stringify({
          xMm: el.positionMm.xMm + delta.xMm,
          yMm: el.positionMm.yMm + delta.yMm,
        }),
      }),
      onNumericOverride: (absoluteMm): GripCommand => ({
        type: 'updateElementProperty',
        elementId: el.id,
        key: 'positionMm',
        value: JSON.stringify({ xMm: absoluteMm, yMm: el.positionMm.yMm }),
      }),
    };
    return [positionGrip];
  },
};

export const leaderTextGripProvider: ElementGripProvider<LeaderText> = {
  grips(el: LeaderText, _ctx: PlanContext): GripDescriptor[] {
    const anchorGrip: GripDescriptor = {
      id: `${el.id}:anchor`,
      positionMm: el.anchorMm,
      shape: 'circle',
      axis: 'free',
      hint: 'Drag to move leader anchor',
      onDrag: () => ({ kind: 'unknown', id: el.id }),
      onCommit: (delta): GripCommand => ({
        type: 'updateElementProperty',
        elementId: el.id,
        key: 'anchorMm',
        value: JSON.stringify({
          xMm: el.anchorMm.xMm + delta.xMm,
          yMm: el.anchorMm.yMm + delta.yMm,
        }),
      }),
      onNumericOverride: (absoluteMm): GripCommand => ({
        type: 'updateElementProperty',
        elementId: el.id,
        key: 'anchorMm',
        value: JSON.stringify({ xMm: absoluteMm, yMm: el.anchorMm.yMm }),
      }),
    };
    const textGrip: GripDescriptor = {
      id: `${el.id}:text`,
      positionMm: el.textMm,
      shape: 'square',
      axis: 'free',
      hint: 'Drag to move text block',
      onDrag: () => ({ kind: 'unknown', id: el.id }),
      onCommit: (delta): GripCommand => ({
        type: 'updateElementProperty',
        elementId: el.id,
        key: 'textMm',
        value: JSON.stringify({
          xMm: el.textMm.xMm + delta.xMm,
          yMm: el.textMm.yMm + delta.yMm,
        }),
      }),
      onNumericOverride: (absoluteMm): GripCommand => ({
        type: 'updateElementProperty',
        elementId: el.id,
        key: 'textMm',
        value: JSON.stringify({ xMm: absoluteMm, yMm: el.textMm.yMm }),
      }),
    };
    return [anchorGrip, textGrip];
  },
};

