      ...wall,
      wallTypeId: wallType.id,
      materialKey: 'timber_frame_insulation',
    };
    const { getByText, queryByText } = render(
      InspectorPropertiesFor(typedWall, t, {
        elementsById: { [wallType.id]: wallType },

