1	/**
2	 * EDT-01 — dimension grip provider.
3	 *
4	 * Two grips: an anchor on the dimensioned start point (`aMm`) and an
5	 * offset grip that moves the dim line perpendicular to the
6	 * measurement axis. The offset grip projects drag deltas onto the
7	 * unit normal of (a → b) so the user can only push the dimension
8	 * up / down (away from the measured edge), never along it.
9	 */
10	import type { Element, XY } from '@bim-ai/core';
11	
12	import type {
13	  ElementGripProvider,
14	  GripCommand,
15	  GripDescriptor,
16	  PlanContext,
17	} from '../gripProtocol';
18	
19	export type Dimension = Extract<Element, { kind: 'dimension' }>;
20	
21	export function dimensionTextOffsetResetCommand(
22	  gripId: string,
23	  elementsById: Record<string, Element>,
24	): GripCommand | null {
25	  if (!gripId.endsWith(':text')) return null;
26	  const elementId = gripId.slice(0, -':text'.length);
27	  const el = elementsById[elementId];
28	  if (!el || el.kind !== 'dimension') return null;
29	  return {
30	    type: 'updateElementProperty',
31	    elementId,
32	    key: 'textOffsetMm',
33	    value: null,
34	  };
35	}
36	
37	function unitNormal(a: XY, b: XY): { nx: number; ny: number } {
38	  const dx = b.xMm - a.xMm;
39	  const dy = b.yMm - a.yMm;
40	  const len = Math.hypot(dx, dy);
41	  if (len === 0) return { nx: 0, ny: 1 };
42	  return { nx: -dy / len, ny: dx / len };
43	}
44	
45	function unitAxis(a: XY, b: XY): { ux: number; uy: number } {
46	  const dx = b.xMm - a.xMm;
47	  const dy = b.yMm - a.yMm;
48	  const len = Math.hypot(dx, dy);
49	  if (len === 0) return { ux: 1, uy: 0 };
50	  return { ux: dx / len, uy: dy / len };
51	}
52	
53	export const dimensionGripProvider: ElementGripProvider<Dimension> = {
54	  grips(dim: Dimension, _context: PlanContext): GripDescriptor[] {
55	    const { nx, ny } = unitNormal(dim.aMm, dim.bMm);
56	    const { ux, uy } = unitAxis(dim.aMm, dim.bMm);
57	
58	    const anchorGrip: GripDescriptor = {
59	      id: `${dim.id}:anchor`,
60	      positionMm: dim.aMm,
61	      shape: 'square',
62	      axis: 'free',
63	      hint: 'Drag dimension start',
64	      onDrag: () => ({ kind: 'unknown', id: dim.id }),
65	      onCommit: (delta): GripCommand => ({
66	        type: 'updateElementProperty',
67	        elementId: dim.id,
68	        key: 'aMm',
69	        value: JSON.stringify({
70	          xMm: dim.aMm.xMm + delta.xMm,
71	          yMm: dim.aMm.yMm + delta.yMm,
72	        }),
73	      }),
74	      onNumericOverride: (absoluteMm): GripCommand => {
75	        // Numeric override = X coordinate; Y left unchanged. Same
76	        // grammar as the column position grip.
77	        return {
78	          type: 'updateElementProperty',
79	          elementId: dim.id,
80	          key: 'aMm',
81	          value: JSON.stringify({ xMm: absoluteMm, yMm: dim.aMm.yMm }),
82	        };
83	      },
84	    };
85	
86	    const offsetGrip: GripDescriptor = {
87	      id: `${dim.id}:offset`,
88	      positionMm: {
89	        xMm: (dim.aMm.xMm + dim.bMm.xMm) / 2 + dim.offsetMm.xMm,
90	        yMm: (dim.aMm.yMm + dim.bMm.yMm) / 2 + dim.offsetMm.yMm,
91	      },
92	      shape: 'arrow',
93	      axis: 'normal_to_element',
94	      hint: 'Drag perpendicular to move dim line',
95	      onDrag: () => ({ kind: 'unknown', id: dim.id }),
96	      onCommit: (delta): GripCommand => {
97	        const projected = delta.xMm * nx + delta.yMm * ny;
98	        return {
99	          type: 'updateElementProperty',
100	          elementId: dim.id,
101	          key: 'offsetMm',
102	          value: JSON.stringify({
103	            xMm: dim.offsetMm.xMm + nx * projected,
104	            yMm: dim.offsetMm.yMm + ny * projected,
105	          }),
106	        };
107	      },
108	      onNumericOverride: (absoluteMm): GripCommand => ({
109	        // Numeric override = perpendicular distance from the measured
110	        // segment (signed along the unit normal).
111	        type: 'updateElementProperty',
112	        elementId: dim.id,
113	        key: 'offsetMm',
114	        value: JSON.stringify({
115	          xMm: nx * absoluteMm,
116	          yMm: ny * absoluteMm,
117	        }),
118	      }),
119	    };
120	
121	    // F-088 — text-label drag grip. Positioned at the current text label
122	    // centre (midpoint of aMm→bMm + offsetMm + textOffsetMm). Drag commits
123	    // are constrained to the dimension line axis so labels stay aligned with
124	    // the measured span.
125	    const textMidXMm = (dim.aMm.xMm + dim.bMm.xMm) / 2 + dim.offsetMm.xMm;
126	    const textMidYMm = (dim.aMm.yMm + dim.bMm.yMm) / 2 + dim.offsetMm.yMm;
127	    const currentTextOffsetX = dim.textOffsetMm?.xMm ?? 0;
128	    const currentTextOffsetY = dim.textOffsetMm?.yMm ?? 0;
129	    const textGrip: GripDescriptor = {
130	      id: `${dim.id}:text`,
131	      positionMm: {
132	        xMm: textMidXMm + currentTextOffsetX,
133	        yMm: textMidYMm + currentTextOffsetY,
134	      },
135	      shape: 'circle',
136	      axis: 'x',
137	      hint: 'Drag along dimension line to reposition text label',
138	      onDrag: () => ({ kind: 'unknown', id: dim.id }),
139	      onCommit: (delta): GripCommand => {
140	        const currentAlong = currentTextOffsetX * ux + currentTextOffsetY * uy;
141	        const draggedAlong = delta.xMm * ux + delta.yMm * uy;
142	        const nextAlong = currentAlong + draggedAlong;
143	        return {
144	          type: 'updateElementProperty',
145	          elementId: dim.id,
146	          key: 'textOffsetMm',
147	          value: JSON.stringify({
148	            xMm: ux * nextAlong,
149	            yMm: uy * nextAlong,
150	          }),
151	        };
152	      },
153	      onNumericOverride: (): GripCommand => ({
154	        // Numeric override not meaningful for a free-axis text grip;
155	        // return a no-op unknown command so the drag still cancels cleanly.
156	        type: 'updateElementProperty',
157	        elementId: dim.id,
158	        key: 'textOffsetMm',
159	        value: JSON.stringify({
160	          xMm: currentTextOffsetX,
161	          yMm: currentTextOffsetY,
162	        }),
163	      }),
164	    };
165	
166	    return [anchorGrip, offsetGrip, textGrip];
167	  },
168	};
169

